  "title": "Getter बनाम Direct Property Access",
  "group": "एडवांस्ड इंटरफेस",
  "options": [
    {
      "text": "लूप का उपयोग करें"
    },
    {
      "text": "वैल्यू एक्सेस करने के लिए मेथड कॉल करें"
    },
    {
      "text": "वैल्यू को सीधे एक्सेस करें"
    },
    {
      "text": "एरर थ्रो करें"
    }
  ],
  "questionProse": [
    "JavaScript में getter वाली प्रॉपर्टी को एक्सेस करने का सही तरीका क्या है?"
  ],
  "explanationProse": [
    "JavaScript में, getter को बिल्कुल एक नॉर्मल प्रॉपर्टी की तरह ही एक्सेस किया जाता है। इसे फंक्शन की तरह कॉल करने की ज़रूरत नहीं पड़ती।\n    इस उदाहरण में, `obj.val` को सीधे एक्सेस करने से getter मेथड ट्रिगर होता है और `got it!` आउटपुट मिलता है।"
  ]
}
